// Extract and validate JSON from AI Agent response
const items = $input.all();
const response = items[0].json.output;

function extractJSON(str) {
  if (typeof str !== 'string') return str;
  let cleaned = str.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch(e) {
      return null;
    }
  }
  return null;
}

let itinerary = extractJSON(response);
if (!itinerary && typeof response === 'string') {
  try {
    itinerary = JSON.parse(response);
  } catch(e) {
    console.log('JSON parse error:', e.message);
  }
}
if (!itinerary || !itinerary.days) {
  itinerary = {
    success: false,
    error: 'Impossible de générer l'itinéraire. Veuillez reformuler votre demande.',
    message: 'Aucun itinéraire valide n'a pu être créé avec les excursions disponibles.',
    rawResponse: typeof response === 'string' ? response.substring(0, 500) : response
  };
} else {
  itinerary.success = true;
}
return [itinerary];
